<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Mini Desktop</title>
<style>
/* Basic reset */
body,html{margin:0;padding:0;height:100%;overflow:hidden;font-family:sans-serif;background:#222;color:#eee;}
#desktop{position:absolute;width:100%;height:100%;background:url('data:image/svg+xml;utf8,<svg xmlns="http://www.w3.org/2000/svg" width="20" height="20"><rect width="10" height="10" fill="%23222"/><rect x="10" y="10" width="10" height="10" fill="%23222"/></svg>');background-size:20px;background-color:#111;}
#taskbar{position:absolute;bottom:0;width:100%;height:40px;background:#333;border-top:1px solid #555;display:flex;align-items:center;padding-left:5px;}
button{margin-right:5px;background:#444;color:#eee;border:none;padding:5px 10px;border-radius:3px;cursor:pointer;}
button:hover{background:#555;}
.window{position:absolute;top:50px;left:50px;width:400px;height:300px;background:#222;border:1px solid #555;border-radius:4px;box-shadow:0 2px 8px rgba(0,0,0,.5);display:none;}
.win-header{background:#444;color:#eee;padding:5px;cursor:move;display:flex;justify-content:space-between;align-items:center;font-size:14px;}
.win-close{background:none;border:none;color:#eee;font-weight:bold;cursor:pointer;}
#files-window,#notepad-window{z-index:10;}
#files-list{padding:5px;height:calc(100% - 30px);overflow:auto;}
.fs-item{padding:2px 4px;margin:1px 0;background:#333;border-radius:3px;cursor:pointer;}
.fs-item:hover{background:#444;}
#tabs{display:flex;background:#444;padding:2px;}
.tab{background:#555;color:#eee;padding:5px 10px;margin-right:2px;border-radius:3px 3px 0 0;cursor:pointer;}
.tab.active{background:#222;}
#new-tab{background:none;border:none;color:#eee;font-weight:bold;cursor:pointer;margin-left:auto;}
#editor{width:100%;height:calc(100% - 30px);border:none;background:#111;color:#eee;padding:5px;resize:none;}
</style>
</head>
<body>
<div id="desktop">
    <div id="taskbar">
        <button id="open-files">Files</button>
        <button id="open-notepad">Notepad</button>
    </div>

    <!-- Files Window -->
    <div id="files-window" class="window">
        <div class="win-header">
            <span>Files</span>
            <button class="win-close">&times;</button>
        </div>
        <div style="display:flex;align-items:center;padding:5px;">
            <button id="files-up">Up</button>
            <span id="files-path" style="margin-left:10px;">/</span>
        </div>
        <div id="files-list"></div>
    </div>

    <!-- Notepad Window -->
    <div id="notepad-window" class="window">
        <div class="win-header">
            <span>Notepad</span>
            <button class="win-close">&times;</button>
        </div>
        <div id="tabs"></div>
        <textarea id="editor"></textarea>
    </div>
</div>

<script>
// ---------- Utility ----------
function $(id){return document.getElementById(id);}
function createEl(tag,cls,text){
  const el=document.createElement(tag);
  if(cls)el.className=cls;
  if(text!==undefined)el.textContent=text;
  return el;
}
function makeDraggable(el){
  let offsetX,offsetY,dragging=false;
  const header=el.querySelector('.win-header');
  header.addEventListener('mousedown',e=>{
    dragging=true;
    offsetX=e.clientX-el.offsetLeft;
    offsetY=e.clientY-el.offsetTop;
    document.body.style.userSelect='none';
  });
  document.addEventListener('mouseup',()=>{dragging=false;document.body.style.userSelect='auto';});
  document.addEventListener('mousemove',e=>{
    if(dragging){
      el.style.left=(e.clientX-offsetX)+'px';
      el.style.top=(e.clientY-offsetY)+'px';
    }
  });
}

// ---------- Window Open/Close ----------
['open-files','open-notepad'].forEach(btnId=>{
  $(btnId).addEventListener('click',()=>{
    const win=btnId==='open-files'?'files-window':'notepad-window';
    $(win).style.display='block';
  });
});
document.querySelectorAll('.win-close').forEach(btn=>{
  btn.addEventListener('click',e=>{
    e.target.closest('.window').style.display='none';
  });
});

// ---------- Files App ----------
const fs = {
  '/':{bin:{},etc:{},home:{user:{Documents:{},Downloads:{},Pictures:{}}},
  '/usr':{},
  '/var':{}
};
let currentPath='/';

function renderFiles(){
  const list=$( 'files-list' );
  list.innerHTML='';
  const items=fs[currentPath];
  for(const name in items){
    const item=createEl('div','fs-item',name);
    if(typeof items[name]==='object'){
      item.dataset.type='folder';
      item.addEventListener('dblclick',()=>{navigateTo(currentPath+name+'/');});
    }else{
      item.dataset.type='file';
    }
    list.appendChild(item);
  }
}
function navigateTo(path){
  currentPath=path;
  $('files-path').textContent=currentPath;
  renderFiles();
}
$('files-up').addEventListener('click',()=>{
  if(currentPath!=='/'){
    const parts=currentPath.split('/').filter(Boolean);
    parts.pop();
    const newPath='/' + parts.join('/') + (parts.length?'/':'');
    navigateTo(newPath||'/');
  }
});
renderFiles();

// ---------- Notepad App ----------
const STORAGE_KEY='mini_notepad_tabs';
let tabs=[];
let activeTabId=null;

function loadTabs(){
  const data=localStorage.getItem(STORAGE_KEY);
  if(data)tabs=JSON.parse(data);
}
function saveTabs(){localStorage.setItem(STORAGE_KEY,JSON.stringify(tabs));}

function renderTabs(){
  const tabBar=$('tabs');
  tabBar.innerHTML='';
  tabs.forEach(tab=>{
    const el=createEl('div','tab',tab.title||'Untitled');
    if(tab.id===activeTabId)el.classList.add('active');
    el.dataset.id=tab.id;
    el.addEventListener('click',()=>{switchTo(tab.id);});
    tabBar.appendChild(el);
  });
  const newBtn=createEl('button','', '+');
  newBtn.title='New Tab';
  newBtn.addEventListener('click',newTab);
  tabBar.appendChild(newBtn);
}
function switchTo(id){
  activeTabId=id;
  renderTabs();
  $('editor').value=tabs.find(t=>t.id===id).content;
}
function newTab(){
  const id=Date.now().toString();
  tabs.push({id,title:'Untitled',content:''});
  switchTo(id);
  saveTabs();
}
$('editor').addEventListener('input',e=>{
  const tab=tabs.find(t=>t.id===activeTabId);
  if(tab){tab.content=e.target.value;saveTabs();}
});

loadTabs();
if(!tabs.length)newTab(); else switchTo(tabs[0].id);

// ---------- Dragging ----------
makeDraggable($('files-window'));
makeDraggable($('notepad-window'));
</script>
</body>
</html>
